module shift_register_8bit(clk, reset, load, shift, D, Q);
     input clk;
     input reset;
     input load;
     input shift;
     input [7:0] D;
     output [7:0] Q;

     reg [7:0] Q;

       wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
         if (reset)
             Q <= 8'b0;
         else if (load)
             Q <= D;
         else if (shift)
             Q <= {Q[6:0], 1'b0};
     end
endmodule
